const Q_GEOGRAPHY_2008=[{"id": "objective>Geography>2008>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The bearing of Olefi from Kosi is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">035<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">085<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">127<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">305<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Bearing of Olefi from Kosi  <br/>  = U + V + W + X  <br/>  = 90 + 90 + 90 + 35  <br/>  = 305<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2008>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The length of River Tere from the edge of the map to the confluence with River Epe is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.70km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.70km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.70km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.70km</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trace River Tere using White thread & Mark Length  <br/>  Scale = 1cm  = 1km  <br/>  Measure thread on metre rule  <br/>  = 6.7cm  <br/>  = 6.7km.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2008>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The likely human activity in the northern part of the map is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lumbering </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fishing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quarring</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lumbering is usually associated with forested regions as found in the Northern part of the map.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2008>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The second largest settlement on the map is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oziza</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kosi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pkeku</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kosi, based on area covered is the second largest settlement on the map.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2008>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following towns are not intervisible?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Epe and Karaga</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oziza and Pkeku</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kera and Kosi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tere and Olefi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kera and Kosi are two towns that are not intervisible because of the sides of the highland slopes they are located.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2008>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The combined petroleum production of Saudi Arabia and Russia in 2003 in million tonnes is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">750</div>", "<div style=\"font-family:Cambria;font-size:17px;\">900</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1050</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Add values from the graph for  <br/>  saudi + Russia = 420 + 480 = 900</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2008>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> If the total production of petroleum is estimated to be 2010 million tonnes, what is the approximate percentage of the production by the USA?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If USA = 290  <br/>  Total = 2010  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">USA</td><td style=\"text-align:center;\">%</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">290<hr size=\"1\" />2010</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div>  <br/>  = 0.1442 × 100  <br/>  = 14.4%  <br/>  = 14%.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2008>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pie-chart shows information in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Percentages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Degrees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Slope angles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Divided bars</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A pie chart shows information in degrees. Each slice of the pie represents a category of data. The size of the slice is proportional to the quantity it represents in the dataset. The entire pie represents 100% of the data, and the pie chart is a circular graph, so each slice forms a 'sector' or 'portion' of the circle, and this is measured in degrees.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2008>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following operations is common to both chain and prismatic compass surveys?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Baseline determination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Forward bearing reading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Backward bearing reading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Offset measurement</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both chain and prismatic compass surveys involve the measurement of offsets. An offset is a short distance measured at right angles from the survey line to help in locating the details of the survey. Baseline determination, forward bearing reading, and backward bearing reading are not common to both.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2008>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The surface zone of the earth that is occupied by living organisms is referred to as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">atmosphere </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lithosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrosphere</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The biosphere consists of the portion of the atmosphere (air), lithosphere(land) and hydrosphere(water) where life/living organisms are found.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2008>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tremendous pressure or temperature change may lead to the formation of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limestone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">granite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gneiss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gneiss is a folinted metamorphic rock from pre-existing formations originally either igneous or sedimentary rocks usually coarse grained consisting majorly of mica, quartz and feldspar.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2008>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentary rocks are distinguished from other rocks by their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">strata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joints</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compact nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystalline nature</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentary rocks are distinguished from other rocks by their strata. Strata refer to layers of sedimentary rock or soil with internally consistent characteristics that distinguish it from other layers.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2008>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rocks often develop cracks when they are exposed to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">compression and movements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joints and faults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compression and tension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joints and cracks</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Compressions and tensions (vibrations within particulate structure) usually results to cracks especially igneous rocks are more prone to this.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2008>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A feature produced as a result of glacial deposition is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a cirque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a moraine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an arete</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a hanging valley</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Moraines are formed by accumulation of unconsolidated glacial debris (soil & rock) as a result of past or current glacial activities on the earth surface. </div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2008>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The drainage pattern is developed from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a mountain top</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an underground drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a volcanic cone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an inselberg</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Volcanic cones when weathered or blasted forms a crater caldera/lakes which results in radial patterned river networks flowing downslope.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2008>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The type of drainage is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dendritic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trellised</div>", "<div style=\"font-family:Cambria;font-size:17px;\">superimposed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Volcanic cones when weathered or blasted forms a crater caldera/lakes which results in radial patterned river networks flowing downslope.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2008>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A type of landform that is associated with large-scale orogeny is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">block mountain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volcanic mountain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fold mountain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">residual mountain</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Orogeny is mountain/highland formation. Fold mountains such as the Himalayas are extensive & formed as a result of tectonic plate movement leading to compression & floodings.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2008>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effects of ocean currents along the coasts they wash are experienced</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">during summer only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">during winter only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">when prevailing winds are onshore </div>", "<div style=\"font-family:Cambria;font-size:17px;\">when prevailing winds are offshore</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ocean currents only have effects upon adjoining coasts when they make land falls.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2008>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a warm current?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">East Australian current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">California current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Peruvian current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Antarctic drift</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The East Australian Current is a warm ocean current that moves water from the Coral Sea down the east coast of Australia. Warm currents are those that flow from low latitudes into high latitudes. They are typically found on the east side of continents in the tropics and subtropics.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2008>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The speed of wind is usually measured using </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a wind vane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a wind rose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an anemometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a thermometer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An anemometer is a device used for measuring the speed of wind, and is also a common weather station instrument. The term is derived from the Greek word anemos, which means wind, and is used to describe any wind speed instrument used in meteorology.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2008>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The climate that is noted for its summer dryness is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Equatorial climate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical monosoon climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cool temperate climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mediterranan climate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mediterranean climate has dry summer and wet winter. Also known as the Dry summer subtropical climate with hot dry summers & mild wet winters.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2008>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the temperature of a place is 68<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>F, what is its equivalent in degree centigrade?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">°F to °C = <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(°F</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">32)</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">5<hr size=\"1\" />9</td></tr></table></div> <br/>  ∴ If 68<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>F = x <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(68</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">32)</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">5<hr size=\"1\" />9</td></tr></table></div>  <br/>  = 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2008>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One distinguishing characteristics of ferruginous soils is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">occurrence of iron concretion in the B-horizon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">predominance of clay in the A-horizon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">well-developed A and B horizons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high content of organic matter in all the horizons</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The iron and aluminium form distinct layer below the layer of humus/top soil. This having well-developed A & B horizons.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2008>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main mineral composition of lateritic soils are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sodium and nickel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium and zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium and calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron and aluminium</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iron and aluminium are the main mineral composition of lateritic soils giving it its characteristic red colour.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2008>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mineral that is essential in cement production is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">talc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gypsum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quartzite</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gypsum is an indispensible component of cement. It is added to control the rate of hardening of cement. It is a soft white or gray mineral made up of integrated calcium sulphate.</div>", "topic": "PRATICAL GEOGRAPHY II : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2008>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Shifting cultivation in agriculture involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">intensive cultivation in a highly populated region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultivating alternative plots to allow natural regeneration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultivating food crops on subsistence basis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultivating cash crops principally for export.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shifting cultivation is an old traditional practise that entails crop cultivation on alternate plots to allow for natural regeneration.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2008>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One direct adverse environmental effect of deforestation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">escalated soil erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced forest income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased farmer-herder conflicts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ozone layer depletion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One direct adverse environmental effect of deforestation is escalated soil erosion. When trees are cut down, the soil is left exposed and can be easily washed away by rain. This leads to soil erosion, which can degrade the land and make it less productive for agriculture.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2008>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A process that creates deep gorges on the land surface is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sheet erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced forest income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased farmer-herder conflicts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ozone layer depletion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sheet erosion is a process of erosion that removes a uniform layer of soil from the surface of an area. This process can lead to the formation of deep gorges on the land surface. The other options do not directly relate to physical geographical processes that shape the land surface.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2008>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most sparsely populated areas of the world include </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Canada and Eurasia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">China and Japan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan and Indonesia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bangladesh and Sri Lanka</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Canada and Eurasia are among the most sparsely populated areas of the world. This is due to their harsh climates and vast, uninhabitable landscapes. The other options, such as China and Japan, are among the most densely populated areas of the world.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2008>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following river basins is most densely populated?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Ganges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Amazon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Niger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Zambezi</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gauges cutting through Nepal/India region have supported a large population density from early times because of the fertile alluvial soil for paddy rice farming. </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2008>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of people from a village to an irrigation project area may be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">urban-urban migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-urban, migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urban-rural migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-rural migration</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of people from a village to an irrigation project area is described as rural-rural migration. This is because both the village and the irrigation project area are in rural settings. Urban-urban migration refers to the movement of people within urban areas. Rural-urban migration refers to the movement of people from rural areas to urban areas. Urban-rural migration refers to the movement of people from urban areas to rural areas.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2008>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Access to water and kinship ties can lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nucleated settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ribbon settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loose-knit settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersed settlements</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Loose-knot settlements meet the criteria for both access to kinship ties (nucleated) and water (ribbon/linear). As such its a merger of both components.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2008>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sydney, Hong Kong and San Francisco have attained considerable importance because of their function as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">important railway junctions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital cities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seaports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cross roads</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sydney, Hong kong & San Francisco are renowned for their high traffic seaports in their respective regions.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2008>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country that has its railways operating on three different gauges is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the USA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Russia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Australia</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Australia runs on all broad, narrow and standard railway gauges within its territorial boundaries.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2008>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The three leading manufacturing nations of the world are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Japan, the USA and Germany</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan, Germany and Britain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">China, the USA and Germany</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan, the USA and Italy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Modern day china, USA & Germany are the 3 leading manufacturing countries of the world.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2008>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industrial location can be influenced by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transportation, raw materials and migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital, raw materials and population growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials, energy and market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market, emigration and labour</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Raw materials & energy (input) and market (sales) to a large extent determine or influence location of industry.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2008>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial agriculture in the tropics concentrates on the production of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wheat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">millet</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tropics are characterized by hot and humid weather and abundant rainfall. Crops like tea, coffee, sugar cane, bananas, mangoes, coconut, and spices are commonly grown in these regions.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2008>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following Nigerian towns is likely to experience frequent cases of coastal erosion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Burutu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Akankpa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lokoja</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ilesha</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Burutu is a town and Local Government Area (LGA) in Delta State, Nigeria. It is a river port on the Forcados River, one of the Niger Delta waterways. Therefore, it is more likely to experience coastal erosion.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2008>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A state in Nigeria notable for hydroelectric power generation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adamawa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kaduna</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Niger state is home to kainji and shiroro dams reputable for Hydro-Electric Power generation in Nigeria.</div>", "topic": "REGIONAL GEOGRAPHY : NIGERIA"}, {"id": "objective>Geography>2008>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zuma rock, Zaria and Kano isenberg's in Nigeria are within the confines of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Western uplands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eastern highlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North central highlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North-east highlands </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zuma rock, Zaria and Kano isenberg's in Nigeria are within the confines of the North central highlands. The North central highlands is a geographical region in Nigeria that includes the Federal Capital Territory and some states in the North Central geopolitical zone of Nigeria. This region is characterized by a highland area with numerous rocks and hills.</div>", "topic": "REGIONAL GEOGRAPHY : NIGERIA"}, {"id": "objective>Geography>2008>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian river with the longest distance of internal waterways is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">River Osun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Ogun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Benue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cross River</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian river with the longest distance of internal waterways is River Benue. River Benue is the major tributary of the Niger River, which is the principal river of western Africa. It flows approximately 1,400 kilometers from its source in the Adamawa Plateau to its confluence with the Niger River.</div>", "topic": "REGIONAL GEOGRAPHY : WATER BODIES"}, {"id": "objective>Geography>2008>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Trees in the mangroove forest have aerial roots because they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have to absorb water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">need more air than water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have to absorb nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">do not require much water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Due to the salinity of swamp/ocean water, mangrove forests have aerial roots to absorb water from the atmosphere.</div>", "topic": "REGIONAL GEOGRAPHY : VEGETATION"}, {"id": "objective>Geography>2008>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A settlement that derives its domestic water from a waterfall in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bida</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Erin-Ijesa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Omu-Aran</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Erin-Ijesa in Osun State, Nigeria is known for its waterfall, the Erin-Ijesa Waterfall, also known as Olumirin Waterfall. Therefore, it's likely that the settlement derives its domestic water from this waterfall.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2008>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Wheat is cultivated through irrigation in Nigeria in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kano state </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kogi State</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kaduna state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nasarawa state</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nasarawa state has irrigation farming to cultivate wheat.</div>", "topic": "REGIONAL GEOGRAPHY : IRRIGATION AGRICULTURE IN THE NILE AND NIGER BASIN"}, {"id": "objective>Geography>2008>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most economically renewable energy substitute to petroleum in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydroelectricity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sunlight</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Though sunlight is renewable, hydro-electricity outplays it on the measure of being economically affordable in the short term.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2008>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equatorial climate is found in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zaire Basin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Namib desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Horn of Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Veld of South Africa</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zaire Basin of Central Africa (DR congo and Republic of Congo) and adjoining areas is home to the Equatorial climate and associated Equatorial rainforest vegetation.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2008>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The arid regions of Africa have great potentials for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nuclear energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydro energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solar energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemical energy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solar energy/radiation is abundant  in the arid regions of Africa. From Sahara to Namib to kalahari etc, the volume of solar energy  due to absence of cloud cover is tremendous.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2008>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Unemployment is at a high level in West African cities because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is a large youthful population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many of the dwellers are skilled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many of the dwellers are unskilled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrialization is at a slow pace</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All other answers/options can be addressed (large youthful population, high population of unskilled and skilled labour) when industrialization is increased at a fast pace to reduce high unemployment levels in West Africa.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2008>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic activities in tropical Africa largely depend on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Primary production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quaternary production</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Most economic activities in Tropical Africa still revolve around Primary  Production (agro-allied and agriculture) related activities.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2008>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Khartoum in Sudan is located</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">between two lakes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the confluence of two rivers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the lowest bridge points</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the bends of rivers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Khartoum, the capital of Sudan, is located at the confluence of the White Nile and the Blue Nile. This is where the two rivers merge to form the Nile River, which flows northward through Egypt to the Mediterranean Sea. A confluence is a location where two or more bodies of water meet.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}];
